function r(e){const t=Math.max(0,e.balanceAmount??e.amount),n=Math.max(0,Math.floor((new Date().getTime()-new Date(e.dueDate).getTime())/(1e3*60*60*24))),o=Math.max(0,e.lateFee??0),a=Math.max(0,e.collectionFee??0),u=Math.max(0,e.otherFees??0),s=t+o+a+u;return{baseAmount:t,lateFee:o,collectionFee:a,otherFees:u,totalAmount:s,daysOverdue:n}}function l(e){return e.filter(n=>n.status==="overdue").reduce((n,o)=>{const a=r(o);return n+a.totalAmount},0)}function c(e){return e.filter(t=>t.status==="overdue").sort((t,n)=>new Date(t.dueDate).getTime()-new Date(n.dueDate).getTime())}function m(e){return e.filter(t=>t.status==="overdue").length}function d(e){const t=c(e);return t.length===0?0:r(t[0]).totalAmount}export{r as a,c as b,l as c,d,m as g};
